import { describe, expect, it } from 'vitest';

import { LayerLRU } from '../src/lru';

describe('LayerLRU', () => {
  it('rejects non-positive capacities', () => {
    expect(() => new LayerLRU(0)).toThrow();
    expect(() => new LayerLRU(-1)).toThrow();
    expect(() => new LayerLRU(1.5)).toThrow();
  });

  it('returns null while under capacity', () => {
    const lru = new LayerLRU(3);
    expect(lru.recordTouch(0)).toBeNull();
    expect(lru.recordTouch(1)).toBeNull();
    expect(lru.recordTouch(2)).toBeNull();
    expect(lru.size).toBe(3);
  });

  it('evicts the oldest layer when capacity is exceeded', () => {
    const lru = new LayerLRU(2);
    expect(lru.recordTouch(10)).toBeNull();
    expect(lru.recordTouch(11)).toBeNull();
    expect(lru.recordTouch(12)).toBe(10);
    expect(lru.recordTouch(13)).toBe(11);
    expect(lru.residentLayers()).toEqual([12, 13]);
  });

  it('treats a re-touch as MRU bump without evicting', () => {
    const lru = new LayerLRU(2);
    lru.recordTouch(0);
    lru.recordTouch(1);
    // Re-touch 0 -> 0 should now be MRU; subsequent insert should evict 1.
    expect(lru.recordTouch(0)).toBeNull();
    expect(lru.recordTouch(2)).toBe(1);
    expect(lru.residentLayers()).toEqual([0, 2]);
  });

  it('clear empties the LRU', () => {
    const lru = new LayerLRU(2);
    lru.recordTouch(0);
    lru.recordTouch(1);
    lru.clear();
    expect(lru.size).toBe(0);
    expect(lru.has(0)).toBe(false);
  });
});
